#' Survival Analysis
#'
#' 
#' @param data .
#' @param elapsed .
#' @param status .
#' @param statusEvent .
#' @param group .
#' @param covariates .
#' @param showKm .
#' @param kmCI .
#' @param kmTable .
#' @param kmType .
#' @param showLogRank .
#' @param showCox .
#' @param coxForest .
#' @param coxAssump .
#' @param showSchoenfeldPlot .
#' @param showRoc .
#' @param rocPredictors .
#' @param rocTime .
#' @param rocCI .
#' @param rocWidth .
#' @param rocPlot .
#' @param palBrewer .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$kmSection$kmSummaryTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$kmSection$kmRiskTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$kmSection$kmPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$logRankTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coxSection$coxFitTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coxSection$coxCoefTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coxSection$coxForestPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$coxSection$coxAssumpTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coxSection$schoenfeldPlots} \tab \tab \tab \tab \tab an array \cr
#'   \code{results$rocSection$rocTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$rocSection$rocPlot} \tab \tab \tab \tab \tab an image \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$logRankTable$asDF}
#'
#' \code{as.data.frame(results$logRankTable)}
#'
#' @export
mSRV <- function(
    data,
    elapsed,
    status,
    statusEvent,
    group,
    covariates,
    showKm = TRUE,
    kmCI = TRUE,
    kmTable = FALSE,
    kmType = "survival",
    showLogRank = TRUE,
    showCox = TRUE,
    coxForest = FALSE,
    coxAssump = FALSE,
    showSchoenfeldPlot = FALSE,
    showRoc = FALSE,
    rocPredictors,
    rocTime = 12,
    rocCI = TRUE,
    rocWidth = 95,
    rocPlot = FALSE,
    palBrewer = "Dark2") {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("mSRV requires jmvcore to be installed (restart may be required)")

    if ( ! missing(elapsed)) elapsed <- jmvcore::resolveQuo(jmvcore::enquo(elapsed))
    if ( ! missing(status)) status <- jmvcore::resolveQuo(jmvcore::enquo(status))
    if ( ! missing(group)) group <- jmvcore::resolveQuo(jmvcore::enquo(group))
    if ( ! missing(covariates)) covariates <- jmvcore::resolveQuo(jmvcore::enquo(covariates))
    if ( ! missing(rocPredictors)) rocPredictors <- jmvcore::resolveQuo(jmvcore::enquo(rocPredictors))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(elapsed), elapsed, NULL),
            `if`( ! missing(status), status, NULL),
            `if`( ! missing(group), group, NULL),
            `if`( ! missing(covariates), covariates, NULL),
            `if`( ! missing(rocPredictors), rocPredictors, NULL))

    for (v in group) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- mSRVOptions$new(
        elapsed = elapsed,
        status = status,
        statusEvent = statusEvent,
        group = group,
        covariates = covariates,
        showKm = showKm,
        kmCI = kmCI,
        kmTable = kmTable,
        kmType = kmType,
        showLogRank = showLogRank,
        showCox = showCox,
        coxForest = coxForest,
        coxAssump = coxAssump,
        showSchoenfeldPlot = showSchoenfeldPlot,
        showRoc = showRoc,
        rocPredictors = rocPredictors,
        rocTime = rocTime,
        rocCI = rocCI,
        rocWidth = rocWidth,
        rocPlot = rocPlot,
        palBrewer = palBrewer)

    analysis <- mSRVClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

